import math
from enum import Enum
from dataclasses import dataclass
from typing import Optional

class TripStatus(Enum):
    REQUESTED = 'REQUESTED'
    DRIVER_ASSIGNED = 'DRIVER_ASSIGNED'
    IN_PROGRESS = 'IN_PROGRESS'
    COMPLETED = 'COMPLETED'

@dataclass
class Location:
    lat: float
    lng: float

    def distance_to(self, other: 'Location') -> float:
        return math.sqrt((self.lat - other.lat)**2 + (self.lng - other.lng)**2)

class Driver:
    def __init__(self, driver_id, name, location):
        self.driver_id = driver_id
        self.name = name
        self.location = location
        self.is_available = True

class Rider:
    def __init__(self, rider_id, name):
        self.rider_id = rider_id
        self.name = name

class Trip:
    def __init__(self, trip_id, rider, driver, pickup, dropoff):
        self.trip_id = trip_id
        self.rider = rider
        self.driver = driver
        self.pickup = pickup
        self.dropoff = dropoff
        self.status = TripStatus.DRIVER_ASSIGNED
        self.fare = 0.0

class RideSharingService:
    BASE_FARE = 30.0
    RATE_PER_KM = 12.0

    def __init__(self):
        self.drivers = []
        self.trips = {}
        self.trip_counter = 1

    def register_driver(self, driver):
        self.drivers.append(driver)

    def request_ride(self, rider, pickup, dropoff) -> Optional[Trip]:
        driver = self._find_nearest_driver(pickup)
        if not driver:
            return None
        driver.is_available = False
        trip = Trip(self.trip_counter, rider, driver, pickup, dropoff)
        self.trips[self.trip_counter] = trip
        self.trip_counter += 1
        return trip

    def complete_trip(self, trip_id):
        trip = self.trips[trip_id]
        trip.status = TripStatus.COMPLETED
        dist = trip.pickup.distance_to(trip.dropoff)
        trip.fare = self.BASE_FARE + dist * self.RATE_PER_KM
        trip.driver.is_available = True
        return trip.fare

    def _find_nearest_driver(self, location):
        available = [d for d in self.drivers if d.is_available]
        if not available:
            return None
        return min(available, key=lambda d: d.location.distance_to(location))

def kth_smallest(matrix, k):
    n = len(matrix)
    lo, hi = matrix[0][0], matrix[n-1][n-1]

    def count_less_equal(mid):
        count = 0
        row, col = n - 1, 0
        while row >= 0 and col < n:
            if matrix[row][col] <= mid:
                count += row + 1
                col += 1
            else:
                row -= 1
        return count

    while lo < hi:
        mid = (lo + hi) // 2
        if count_less_equal(mid) < k:
            lo = mid + 1
        else:
            hi = mid
    return lo

matrix = [
    [1,  5,  9],
    [10, 11, 13],
    [12, 13, 15]
]
print(kth_smallest(matrix, 8))  # 13

from collections import Counter
import heapq

# Min-heap O(n log k)
def top_k_frequent_heap(nums, k):
    count = Counter(nums)
    return heapq.nlargest(k, count.keys(), key=count.get)

# Bucket sort O(n)
def top_k_frequent(nums, k):
    count = Counter(nums)
    buckets = [[] for _ in range(len(nums) + 1)]
    for num, freq in count.items():
        buckets[freq].append(num)

    result = []
    for i in range(len(buckets) - 1, 0, -1):
        for num in buckets[i]:
            result.append(num)
            if len(result) == k:
                return result
    return result

print(top_k_frequent([1,1,1,2,2,3], 2))  # [1, 2]

def find_median_sorted_arrays(nums1, nums2):
    if len(nums1) > len(nums2):
        nums1, nums2 = nums2, nums1  # ensure nums1 is smaller

    m, n = len(nums1), len(nums2)
    lo, hi = 0, m
    half = (m + n + 1) // 2

    while lo <= hi:
        i = (lo + hi) // 2
        j = half - i

        nums1_left = nums1[i-1] if i > 0 else float('-inf')
        nums1_right = nums1[i] if i < m else float('inf')
        nums2_left = nums2[j-1] if j > 0 else float('-inf')
        nums2_right = nums2[j] if j < n else float('inf')

        if nums1_left <= nums2_right and nums2_left <= nums1_right:
            if (m + n) % 2 == 1:
                return max(nums1_left, nums2_left)
            return (max(nums1_left, nums2_left) + min(nums1_right, nums2_right)) / 2
        elif nums1_left > nums2_right:
            hi = i - 1
        else:
            lo = i + 1

def longest_palindrome(s):
    if not s:
        return ''
    start, end = 0, 0

    def expand(left, right):
        while left >= 0 and right < len(s) and s[left] == s[right]:
            left -= 1
            right += 1
        return left + 1, right - 1  # last valid palindrome bounds

    for i in range(len(s)):
        # Odd length palindrome
        l1, r1 = expand(i, i)
        # Even length palindrome
        l2, r2 = expand(i, i + 1)

        if r1 - l1 > end - start:
            start, end = l1, r1
        if r2 - l2 > end - start:
            start, end = l2, r2

    return s[start:end+1]

print(longest_palindrome("babad"))   # 'bab' or 'aba'
print(longest_palindrome("cbbd"))    # 'bb'
